//A. Counting Orders #include<bits/stdc++.h>using namespace std;#define int long long intsigned main(){    int t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<int>a(n),b(n);        for(int i=0;i<n;i++){            cin>>a[i];        }        for(int i=0;i<n;i++){            cin>>b[i];        }        sort(a.begin(),a.end());        sort(b.rbegin(),b.rend());        int count=1;        for(int i=0;i<n;i++){            int idx=upper_bound(a.begin(),a.end(),b[i])-a.begin();            int b=n-idx;            count=count*max(b-i,(int)0)%1000000007;        }        cout<<count<<endl;    }}